const apodRaw = $('NASA - APOD').first()?.json || {};
const asteroids = $('NASA - Asteroid Neo Feed').all().map(i => i.json).filter(a => a && a.id);
const flareList = $('NASA - DONKI Solar Flare').all().map(i => i.json).filter(f => f && f.classType);

let korean = '';
try {
  const aiOut = $('OpenAI - Translate APOD').first()?.json || {};
  const content = aiOut?.choices?.[0]?.message?.content
    || aiOut?.message?.content
    || aiOut?.content
    || '';
  if (content) {
    const parsed = typeof content === 'string' ? JSON.parse(content) : content;
    korean = parsed.korean || parsed.ko || '';
  }
} catch (e) {
  korean = '';
}

const today = new Date().toISOString().split('T')[0];
const apodOk = !!(apodRaw && apodRaw.title && !apodRaw.error);

const classRank = { A: 1, B: 2, C: 3, M: 4, X: 5 };
const classColor = { A: '#94a3b8', B: '#38bdf8', C: '#84cc16', M: '#ff9040', X: '#ff3030' };
const classBase = { A: 0.001, B: 0.01, C: 0.1, M: 1, X: 10 };

let topClass = '';
for (const f of flareList) {
  const letter = (f.classType || '').charAt(0).toUpperCase();
  if (classRank[letter] > (classRank[topClass] || 0)) topClass = letter;
}
const coronaColor = topClass === 'X' ? '#ff3030' : topClass === 'M' ? '#ff9040' : '#ffd040';

const sortedAsteroids = [...asteroids].sort((a, b) => {
  const ad = parseFloat(a.close_approach_data?.[0]?.miss_distance?.lunar || '999');
  const bd = parseFloat(b.close_approach_data?.[0]?.miss_distance?.lunar || '999');
  return ad - bd;
});

const totalAsteroids = asteroids.length;
const hazardous = asteroids.filter(a => a.is_potentially_hazardous_asteroid).length;
const flareCount = flareList.length;

const neoCards = sortedAsteroids.map(a => {
  const meters = a.estimated_diameter?.meters;
  const diameter = meters
    ? Math.round((meters.estimated_diameter_min + meters.estimated_diameter_max) / 2)
    : null;
  const cad = a.close_approach_data?.[0] || {};
  const ld = cad.miss_distance?.lunar ? parseFloat(cad.miss_distance.lunar).toFixed(2) : null;
  const kps = cad.relative_velocity?.kilometers_per_second
    ? parseFloat(cad.relative_velocity.kilometers_per_second).toFixed(1)
    : null;
  return {
    name: a.name || '(unknown)',
    diameter,
    ld,
    kps,
    hazardous: !!a.is_potentially_hazardous_asteroid,
  };
});

const flareScatter = flareList.map(f => {
  const ct = f.classType || 'C1';
  const letter = ct.charAt(0).toUpperCase();
  const mag = parseFloat(ct.slice(1)) || 1;
  const intensity = (classBase[letter] || 0.1) * mag;
  const t = f.peakTime ? new Date(f.peakTime).getTime() : Date.now();
  return {
    value: [t, intensity],
    classType: ct,
    sourceLocation: f.sourceLocation || '',
    peakTime: f.peakTime || '',
    itemStyle: { color: classColor[letter] || '#94a3b8' },
    symbolSize: Math.max(8, mag * 10),
  };
});

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
const apodEn = apodOk ? (apodRaw.explanation || '') : '';
const apodKo = korean;
const hasKo = apodKo.trim().length > 0;

