</header>

<div class="grid">
  <div id="hero-card">
    <div class="sample">
      <span>코로나</span>
      <button data-class="auto" class="on">자동</button>
      <button data-class="X">X</button>
      <button data-class="M">M</button>
      <button data-class="other">그 외</button>
      <button data-class="astrophage">아스트로파지</button>
    </div>
    <div id="hero"></div>
    <div id="hero-label"><span class="dot"></span><span class="k">SDO · AIA 171 Å</span> · ARCHIVED ${today}</div>
  </div>

  <div id="apod-card" class="card">
    <h2 data-idx="01">오늘의 천문사진 (APOD)</h2>
    ${apodOk ? `
      <div class="apod-body">
        <div class="apod-img-wrap">${apodRaw.media_type === 'image' && apodRaw.url ? `<img src="${esc(apodRaw.url)}" alt="${esc(apodRaw.title)}">` : ''}</div>
