    <div class="card-body">
    ${neoCards.length ? `<div class="neo-grid">${neoCards.map(c => `
      <div class="neo-card">
        ${c.hazardous ? '<span class="haz">위험</span>' : ''}
        <div class="name">${esc(c.name)}</div>
