        <div class="row"><span class="k">속도</span><span>${c.kps != null ? c.kps + ' km/s' : '—'}</span></div>
      </div>`).join('')}</div>` : `<div class="empty">데이터 없음</div>`}
    </div>
  </div>
</div>

<script>
(function(){
  // Shared fade state for 자동/X/M/그외/아스트로파지
  const fade = {
    sunOpacity: 1.0, sunOpacityTarget: 1.0,
    starSpeed: 1.0, starSpeedTarget: 1.0,
  };
  // --- Star canvas ---
  const starsCanvas = document.getElementById('stars');
  if (starsCanvas) {
    const ctx = starsCanvas.getContext('2d');
    let W = 0, H = 0;
    const stars = [];
    function resize(){
      W = starsCanvas.clientWidth; H = starsCanvas.clientHeight;
      starsCanvas.width = W * devicePixelRatio; starsCanvas.height = H * devicePixelRatio;
      ctx.setTransform(1, 0, 0, 1, 0, 0);
      ctx.scale(devicePixelRatio, devicePixelRatio);
    }
    function seed(){
      stars.length = 0;
      const n = Math.min(140, Math.round((W * H) / 6000));
      for (let i=0;i<n;i++) stars.push({ x: Math.random()*W, y: Math.random()*H, r: Math.random()*1.3+0.2, phase: Math.random()*Math.PI*2, speed: 0.5 + Math.random()*1.5 });
    }
    resize(); seed();
    window.addEventListener('resize', ()=>{ resize(); seed(); });
    function tick(t){
      ctx.clearRect(0,0,W,H);
      for (const s of stars){
        const a = 0.35 + 0.65 * (0.5 + 0.5*Math.sin(t*0.001*s.speed*fade.starSpeed + s.phase));
        ctx.beginPath();
        ctx.fillStyle = 'rgba(255,230,200,' + a.toFixed(3) + ')';
        ctx.arc(s.x, s.y, s.r, 0, Math.PI*2);
        ctx.fill();
      }
      requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  // --- Three.js Sun ---
  const hero = document.getElementById('hero');
  if (hero && window.THREE) {
    const getSize = () => ({ w: hero.clientWidth || 320, h: hero.clientHeight || 320 });
    let { w, h } = getSize();
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(45, w/h, 0.1, 100);
    camera.position.z = 5.5;
    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
    renderer.setSize(w, h);
    hero.appendChild(renderer.domElement);

    const textureLoader = new THREE.TextureLoader();
    textureLoader.crossOrigin = 'anonymous';
    const sunTex = textureLoader.load('./assets/sun.jpg');
    const sunMat = new THREE.SpriteMaterial({
      map: sunTex,
      transparent: true,
      blending: THREE.AdditiveBlending,
      depthWrite: false,
    });
    const sun = new THREE.Sprite(sunMat);
    sun.scale.set(4, 4, 1);
    sun.renderOrder = 0;
    scene.add(sun);

    const coronaColor = new THREE.Color('${coronaColor}');
    const coronaMat = new THREE.ShaderMaterial({
      uniforms: { uColor: { value: coronaColor }, uTime: { value: 0 } },
      vertexShader: 'varying vec3 vN; void main(){ vN = normalize(normalMatrix * normal); gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }',
      fragmentShader: 'varying vec3 vN; uniform vec3 uColor; uniform float uTime; void main(){ float rim = pow(1.0 - abs(vN.z), 4.0); float pulse = 0.9 + 0.1*sin(uTime*1.6); gl_FragColor = vec4(uColor * rim * pulse, rim * 0.55); }',
      transparent: true,
      blending: THREE.AdditiveBlending,
      side: THREE.BackSide,
      depthWrite: false,
      depthTest: false,
    });
    const corona = new THREE.Mesh(new THREE.SphereGeometry(2.25, 64, 64), coronaMat);
    corona.renderOrder = 1;
    scene.add(corona);

    const outerMat = new THREE.ShaderMaterial({
      uniforms: { uColor: { value: coronaColor } },
      vertexShader: 'varying vec3 vN; void main(){ vN = normalize(normalMatrix * normal); gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }',
      fragmentShader: 'varying vec3 vN; uniform vec3 uColor; void main(){ float f = pow(1.0 - abs(vN.z), 8.0); gl_FragColor = vec4(uColor, f*0.35); }',
      transparent: true,
      blending: THREE.AdditiveBlending,
      side: THREE.BackSide,
      depthWrite: false,
      depthTest: false,
    });
    const outerGlow = new THREE.Mesh(new THREE.SphereGeometry(2.9, 48, 48), outerMat);
    outerGlow.renderOrder = 2;
    scene.add(outerGlow);

    const resizeHero = () => {
      const s = getSize();
      renderer.setSize(s.w, s.h);
      camera.aspect = s.w / s.h;
      camera.updateProjectionMatrix();
    };
    window.addEventListener('resize', resizeHero);

    // Corona sample selector
    const sampleMap = { X: '#ff3030', M: '#ff9040', other: '#ffd040' };
    const astrophageColor = '#8a98a8';
    const autoColor = '${coronaColor}';
    const targetColor = new THREE.Color(autoColor);
    const currentColor = new THREE.Color(autoColor);
    const setStatColor = (hex) => {
      document.querySelectorAll('.stat .num').forEach(el => {
        el.style.color = hex;
        el.style.textShadow = '0 0 10px ' + hex + 'aa';
      });
    };
    const applyCorona = (hex) => {
      targetColor.set(hex);
      fade.sunOpacityTarget = 1.0;
      fade.starSpeedTarget = 1.0;
      setStatColor(hex);
    };
    const applyAstrophage = () => {
      targetColor.set(astrophageColor);
      fade.sunOpacityTarget = 0.6;
      fade.starSpeedTarget = 0.5;
      setStatColor(astrophageColor);
    };
    const sampleButtons = document.querySelectorAll('.sample button');
    sampleButtons.forEach(b => {
      b.addEventListener('click', () => {
        sampleButtons.forEach(x => x.classList.remove('on'));
        b.classList.add('on');
        const k = b.dataset.class;
        if (k === 'astrophage') applyAstrophage();
        else applyCorona(k === 'auto' ? autoColor : sampleMap[k]);
      });
    });
    const urlClass = (new URLSearchParams(location.search)).get('class');
    if (urlClass) {
      const upper = urlClass.toUpperCase();
      const key = upper === 'ASTROPHAGE' ? 'astrophage'
                : upper === 'X' ? 'X'
                : upper === 'M' ? 'M'
                : 'other';
      sampleButtons.forEach(x => x.classList.toggle('on', x.dataset.class === key));
      if (key === 'astrophage') applyAstrophage();
      else applyCorona(sampleMap[key]);
    }

    const start = performance.now();
    const lerpRate = 0.015; // ~2.5s fade at 60fps
    function loop(){
      const t = (performance.now() - start) / 1000;
      fade.sunOpacity += (fade.sunOpacityTarget - fade.sunOpacity) * lerpRate;
      fade.starSpeed += (fade.starSpeedTarget - fade.starSpeed) * lerpRate;
      currentColor.lerp(targetColor, lerpRate);
      sunMat.opacity = fade.sunOpacity;
      coronaMat.uniforms.uColor.value.copy(currentColor);
      outerMat.uniforms.uColor.value.copy(currentColor);
      corona.rotation.y -= 0.001;
      coronaMat.uniforms.uTime.value = t;
      renderer.render(scene, camera);
      requestAnimationFrame(loop);
    }
    loop();
  }

  // --- APOD toggle ---
  const btn = document.getElementById('apod-btn');
  if (btn) {
    const ko = document.getElementById('apod-ko');
    const en = document.getElementById('apod-en');
    btn.addEventListener('click', () => {
      const showingKo = ko.style.display !== 'none';
      ko.style.display = showingKo ? 'none' : '';
      en.style.display = showingKo ? '' : 'none';
      btn.textContent = showingKo ? '한국어 보기' : '원문 보기';
    });
  }

  // --- Flare scatter ---
  const flareEl = document.getElementById('flare-chart');
  if (flareEl && window.echarts) {
    const chart = echarts.init(flareEl, 'dark');
    const data = ${JSON.stringify(flareScatter)};
    chart.setOption({
      backgroundColor: 'transparent',
      textStyle: { color: '#e6e6e6' },
      grid: { left: 44, right: 16, top: 20, bottom: 30 },
      tooltip: {
        trigger: 'item',
        formatter: function(p){
          const d = p.data || {};
          const when = d.peakTime ? new Date(d.peakTime).toLocaleString('ko-KR') : '';
          return '<b>' + d.classType + '</b><br/>' + when + (d.sourceLocation ? '<br/>' + d.sourceLocation : '');
        }
      },
      xAxis: { type: 'time', axisLabel: { color: '#94a3b8', fontSize: 10 }, splitLine: { lineStyle: { color: '#1f2937' } } },
      yAxis: { type: 'log', axisLabel: { color: '#94a3b8', fontSize: 10 }, splitLine: { lineStyle: { color: '#1f2937' } } },
      series: [{ type: 'scatter', data: data, emphasis: { focus: 'self' } }]
    });
    window.addEventListener('resize', () => chart.resize());
  }
})();
</script>
</body>
</html>`;

const base64 = Buffer.from(html, 'utf-8').toString('base64');

const summary = `🪐 APOD: ${apodOk ? apodRaw.title : '(불러오기 실패)'}\n☄️ 근접 소행성 ${totalAsteroids}개 (잠재 위험 ${hazardous}개)\n☀️ 지난 30일 태양 플레어 ${flareCount}건 (최고 등급: ${topClass || '없음'})`;

// window-label used in the report title is handled by HTML template above.

return [{
  json: {
    today,
    apodTitle: apodOk ? apodRaw.title : '',
    apodUrl: apodOk ? (apodRaw.url || '') : '',
    totalAsteroids,
    hazardous,
    flareCount,
    topClass: topClass || '',
    summary
  },
  binary: {
    data: {
      data: base64,
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
